pure fn factorial(n: Number) -> Number {
    if n <= 1 { return 1 }
    return n * factorial(n - 1)
}
entry main(x: Text) { return factorial(7) }

pure fn reverse_text(s: Text) -> Text {
    chars = split(s, "")
    result = []
    for i in range(0, length(chars)) {
        result = append(result, get(chars, length(chars) - 1 - i))
    }
    return join(result, "")
}
entry main(x: Text) { return reverse_text("hello world") }

pure fn is_even(n: Number) -> Boolean { return n % 2 == 0 }
pure fn sum_evens(lo: Number, hi: Number) -> Number { total = 0 for n in range(lo, hi + 1) { if is_even(n) { total = total + n } } return total }
entry main(x: Text) { return sum_evens(1, 100) }

pure fn average(nums: Any) -> Number {
    total = 0
    for n in nums { total = total + n }
    return total / length(nums)
}
entry main(x: Text) {
    nums = [85, 92, 78, 95, 88]
    return average(nums)
}

pure fn unique(items: [Number]) -> [Number] {
    seen = []
    for item in items {
        if item not in seen { seen = append(seen, item) }
    }
    return seen
}
entry main(x: Text) { return unique([1, 3, 2, 3, 1, 4, 2, 5]) }

"pure fn count_chars(s: Text) -> Text {
    counts = []
    for c in split(lower(s), "") {
        found = false
        for i in range(0, length(counts)) {
            if get(counts, i) == c { found = true }
        }
        if not found { counts = append(counts, c) }
    }
    result = []
    for c in counts {
        total = 0
        for ch in split(lower(s), "") { if ch == c { total = total + 1 } }
        result = append(result, join([c, ": ", to_text(total)], ""))
    }
    return join(result, ", ")
}
entry main(x: Text) { return count_chars("mississippi") }"

"pure fn parse_scores(text: Text) -> [Text] {
    items = split(text, ",")
    result = []
    for item in items {
        parts = split(item, ":")
        name = get(parts, 0)
        score = to_number(get(parts, 1))
        result = append(result, join([name, ":", to_text(score)], ""))
    }
    return result
}
intent classify_pass_fail(name: Text, score: Number) -> Text { goal: pass_fail } pure fn classify_all(scores: [Text]) -> [Text] { result = [] for s in scores { parts = split(s, ":") name = get(parts, 0) score = to_number(get(parts, 1)) result = append(result, join([name, ":", classify_pass_fail(name, score)], "")) } return result } entry main(text: Text) { scores = parse_scores(text) return join(classify_all(scores), ", ") }"

pure fn longest_word(s: Text) -> Text {
    words = split(lower(s), " ")
    longest = ""
    for w in words {
        if length(w) > length(longest) { longest = w }
    }
    return longest
}
intent explain_word(word: Text) -> Text { goal: definition_and_meaning }
entry main(x: Text) { return join([longest_word(x), " - ", explain_word(longest_word(x))], "") }

pure fn char_freq(s: Text) -> Text {
    counts = {}
    for c in split(lower(s), "") {
        if has_key(counts, c) { counts[c] = get(counts, c) + 1 } else { counts[c] = 1 }
    }
    return join([to_text(k), ":", to_text(v), " " for k in keys(counts)], "")
}
intent describe_pattern(text: Text) -> Text { goal: one_word_pattern_description }
entry main(text: Text) { return join([char_freq(text), " ", describe_pattern(char_freq(text))], "") }

"pure fn sort_desc(nums: [Number]) -> [Number] {
    return reverse(sort(nums))
}
pure fn percentile_of(value: Number, sorted: [Number]) -> Number {
    rank = 0
    for n in sorted {
        if n >= value { rank = rank + 1 }
    }
    return to_number(rank) / length(sorted)
}
entry main(x: Text) {
    nums = [42, 17, 8, 93, 55]
    sorted = sort_desc(nums)
    return join([to_text(sorted), " — 42 is at percentile ", to_text(percentile_of(42, sorted))], "")
}"

"pure fn parse_pairs(text: Text) -> [Text] {
    items = split(text, ",")
    result = []
    for item in items {
        parts = split(item, ":")
        if length(parts) == 2 { result = append(result, join(parts, "")) }
    }
    return result
}
pure fn count_grade(text: Text, grade: Text) -> Number {
    total = 0
    for c in split(text, "") {
        if c == grade { total = total + 1 }
    }
    return total
}
intent summarize_performance(summary: Text) -> Text { goal: brief_performance_summary }
entry main(text: Text) {
    pairs = parse_pairs(text)
    a_count = count_grade(text, "A")
    summary = join(["A count: ", to_text(a_count), " — total: ", to_text(length(pairs))], "")
    return join([summary, " — ", summarize_performance(summary)], "")
}"

"pure fn intersect(a: [Number], b: [Number]) -> [Number] {
    results = []
    for x in a {
        if x in b { results = append(results, x) }
    }
    return results
}
intent describe_overlap(what: Text) -> Text { goal: metaphor_for_overlap }
entry main(x: Text) {
    common = intersect([1,2,3,4,5], [3,4,5,6,7])
    return join([to_text(common), " — ", describe_overlap("overlap")], "")
}"

"pure fn parse_pairs(text: Text) -> [Text] {
    items = split(text, ",")
    result = []
    for item in items {
        parts = split(item, ":")
        if length(parts) == 2 { result = append(result, join(parts, "")) }
    }
    return result
}
pure fn split_pair(pair: Text) -> [Text] {
    return split(pair, "")
}
pure fn sort_by_lat(pairs: [Text]) -> [Text] {
    return sort(pairs, fn(p: Text) -> Number { return to_number(split_pair(p)[1]) })
}
intent describe_pattern(text: Text) -> Text { goal: geographic_pattern_description }entry main(text: Text) {
    parsed = parse_pairs(text)
    sorted = sort_by_lat(parsed)
    return join([to_text(sorted), " — ", describe_pattern(to_text(sorted))], "")
}"
